import React, { useState, useEffect, useCallback } from 'react';
import { IconButton, Box, List, ListItem } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWInput from '../../FAWInput';
import FAWAlert from '../../FAWAlert';
import FAWLoader from '../../FAWLoader';
import { colors } from '../../../../utils/designTokens';
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

const FindAdditionalFieldsView = ({
  onBack,
  workItemId = 0,
  searchUrl = '/WorkItem/SearchUDFsApi'
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [initialResults, setInitialResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [hasSearched, setHasSearched] = useState(false);

  const handleSearch = useCallback(async (termToSearch = '') => {
    setLoading(true);
    setError(null);
    setHasSearched(true);

    try {
      const response = await fetch(searchUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          workItemId: workItemId.toString(),
          term: termToSearch ? termToSearch.trim() : ''
        })
      });

      if (!response.ok) {
        throw new Error('Search request failed');
      }

      const data = await response.json();
      
      if (!data.success) {
        throw new Error(data.message || 'Search failed');
      }

      const results = (data.results || [])
        .map(result => ({
          id: result.Id,
          name: result.Name,
          taskId: result.Id,
          isHighlighted: result.IsHighlighted || false,
          order: result.Order || 0
        }))
        .sort((a, b) => {
          if (a.isHighlighted && !b.isHighlighted) return -1;
          if (!a.isHighlighted && b.isHighlighted) return 1;
          return a.order - b.order;
        });
      
      setSearchResults(results);
      
      if (!termToSearch || !termToSearch.trim()) {
        setInitialResults(results);
      }
    } catch (err) {
      setError('Failed to search fields. Please try again.');
      console.error('FindAdditionalFieldsView search error:', err);
      setSearchResults([]);
    } finally {
      setLoading(false);
    }
  }, [workItemId, searchUrl]);

  useEffect(() => {
    if (workItemId) {
      handleSearch('');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [workItemId]);

  const handleResultClick = (result) => {
    if (window.displayTask && typeof window.displayTask === 'function') {
      window.displayTask(result.taskId);
      setSearchTerm('');
      if (onBack) {
        if (typeof onBack === 'string' && window[onBack]) {
          window[onBack]();
        } else if (typeof onBack === 'function') {
          onBack();
        }
      }
    }
  };

  const handleKeyPress = (event) => {
    if (event.key === 'Enter') {
      handleSearch(searchTerm);
    }
  };

  const handleInputChange = (e) => {
    setSearchTerm(e.target.value);
  };

  useEffect(() => {
    if (!workItemId || !hasSearched) return;
    
    if (!searchTerm || !searchTerm.trim()) {
      setSearchResults(initialResults);
      return;
    }

    const timeoutId = setTimeout(() => {
      handleSearch(searchTerm);
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [searchTerm, workItemId, hasSearched, handleSearch, initialResults]);

  const handleCancel = () => {
    if (onBack) {
      if (typeof onBack === 'string' && window[onBack]) {
        window[onBack]();
      } else if (typeof onBack === 'function') {
        onBack();
      }
    }
  };

  return (
    <Box sx={{ width: '100%' }}>
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 3,
          paddingY: 1,
        }}
      >
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            gap: 1.5,
            flex: 1,
          }}
        >
          {onBack && (
            <IconButton
              onClick={handleCancel}
              disabled={loading}
              sx={{
                padding: 1,
                '&:hover': {
                  backgroundColor: 'rgba(0, 0, 0, 0.04)',
                },
              }}
              aria-label="Go back"
            >
              <ArrowLeftIcon size="md" />
            </IconButton>
          )}
          <FAWTypography
            variant="h6"
            sx={{
              fontWeight: 600,
              fontSize: '22px',
              lineHeight: '28px',
              color: colors.type.default,
            }}
          >
            Find Additional Fields
          </FAWTypography>
        </Box>
      </Box>

      <Box sx={{ p: 3 }}>
        {error && (
          <FAWAlert severity="error" message={error} onClose={() => setError(null)} sx={{ mb: 2 }} />
        )}

        <Box sx={{ mb: 2 }}>
          <FAWInput
            fullWidth
            placeholder="Search for fields..."
            value={searchTerm}
            onChange={handleInputChange}
            onKeyPress={handleKeyPress}
            disabled={loading}
            sx={{
              '& .MuiOutlinedInput-root': {
                paddingLeft: '12px',
                '& .MuiInputAdornment-root': {
                  marginRight: '8px'
                }
              }
            }}
            InputProps={{
              startAdornment: (
                <Box sx={{ display: 'flex', alignItems: 'center', marginRight: 1, color: colors.type.secondary }}>
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M21 21L16.514 16.506L21 21ZM19 10.5C19 15.194 15.194 19 10.5 19C5.806 19 2 15.194 2 10.5C2 5.806 5.806 2 10.5 2C15.194 2 19 5.806 19 10.5Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </Box>
              )
            }}
          />
        </Box>

        <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
          Click a highlighted task to navigate to it.
        </FAWTypography>

        {loading && (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
            <FAWLoader label="Searching fields..." size={40} inline={false} />
          </Box>
        )}

        {!loading && searchResults.length > 0 && (
          <Box sx={{ 
            backgroundColor: colors.background.secondary,
            borderRadius: 1,
            padding: 2,
            mb: 2
          }}>
            <Box sx={{ 
              backgroundColor: colors.background.default,
              borderRadius: 1,
              overflow: 'hidden'
            }}>
              <List sx={{ py: 0 }}>
                {searchResults.map((result) => (
                  <ListItem 
                    key={result.id} 
                    disablePadding
                    sx={{
                      borderBottom: `1px solid ${colors.ui.border.static}`,
                      '&:last-child': {
                        borderBottom: 'none'
                      },
                      cursor: result.isHighlighted ? 'pointer' : 'default',
                      '&:hover': result.isHighlighted ? { 
                        backgroundColor: colors.background.secondary 
                      } : {}
                    }}
                    onClick={() => result.isHighlighted && handleResultClick(result)}
                  >
                    <Box sx={{ 
                      width: '100%',
                      py: 1.5,
                      px: 2,
                      ...(result.isHighlighted && {
                        cursor: 'pointer'
                      })
                    }}>
                      <FAWTypography 
                        variant="body2" 
                        sx={{ 
                          fontWeight: 400,
                          fontSize: '14px',
                          lineHeight: '20px',
                          color: colors.type.default,
                          ...(result.isHighlighted && {
                            fontWeight: 600,
                            color: colors.action.link.default
                          })
                        }}
                      >
                        {result.name}
                      </FAWTypography>
                    </Box>
                  </ListItem>
                ))}
              </List>
            </Box>
          </Box>
        )}

        {!loading && hasSearched && searchTerm && searchResults.length === 0 && !error && (
          <Box sx={{ textAlign: 'center', p: 3 }}>
            <FAWTypography variant="body2" color="text.secondary">
              No fields found matching "{searchTerm}"
            </FAWTypography>
          </Box>
        )}

      </Box>
    </Box>
  );
};

export default FindAdditionalFieldsView;

