import React, { useState, useEffect } from 'react';
import { IconButton, Box, Checkbox, FormControlLabel, FormGroup } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWButton from '../../FAWButton';
import { showToast } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

const WorkflowSummaryView = ({
    onBack,
    workItemId,
    options = [],
    generateUrl = '/WorkItem/GenerateCaseSummary'
}) => {
    const [selectedOptions, setSelectedOptions] = useState({});
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Initialize selected options from props
    useEffect(() => {
        const initialSelected = {};
        options.forEach(option => {
            initialSelected[option.code] = option.selected || false;
        });
        setSelectedOptions(initialSelected);
    }, [options]);

    const handleCheckboxChange = (code, checked) => {
        setSelectedOptions(prev => ({
            ...prev,
            [code]: checked
        }));

        // Handle dependencies if needed
        options.forEach(option => {
            if (option.dependentOn === code && !checked) {
                setSelectedOptions(prev => ({
                    ...prev,
                    [option.code]: false
                }));
            }
        });
    };

    const handleGenerate = async () => {
        setIsSubmitting(true);
        try {
            // Get CSRF token
            const csrfToken = document.querySelector('input[name="__RequestVerificationToken"]');
            const csrfValue = csrfToken ? csrfToken.value : '';

            // Build form data
            const formData = new FormData();
            formData.append('__RequestVerificationToken', csrfValue);
            formData.append('WorkItemId', workItemId);

            // Add options
            options.forEach((option, index) => {
                formData.append(`Options[${index}].Code`, option.code || '');
                formData.append(`Options[${index}].Selected`, selectedOptions[option.code] ? 'true' : 'false');
            });

            // Make AJAX request to generate PDF
            const response = await fetch(generateUrl, {
                method: 'POST',
                body: formData,
                credentials: 'same-origin'
            });

            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }

            // Get the PDF blob
            const blob = await response.blob();

            // Create download link
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;

            // Extract filename from Content-Disposition header or use default
            const contentDisposition = response.headers.get('Content-Disposition');
            let filename = 'WorkflowSummary.pdf';
            if (contentDisposition) {
                const filenameMatch = contentDisposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
                if (filenameMatch && filenameMatch[1]) {
                    filename = filenameMatch[1].replace(/['"]/g, '');
                }
            }

            link.download = filename;
            link.style.display = 'none';
            document.body.appendChild(link);
            link.click();

            // Cleanup
            document.body.removeChild(link);
            window.URL.revokeObjectURL(url);

            setIsSubmitting(false);
            showToast.success('Workflow summary generated successfully', 30000);

            // Optionally go back to main view after download starts
            if (onBack && typeof onBack === 'string' && window[onBack]) {
                setTimeout(() => {
                    window[onBack]();
                }, 500);
            }
        } catch (error) {
            console.error('Error generating workflow summary:', error);
            setIsSubmitting(false);
            showToast.error('Error generating workflow summary. Please try again.', 30000);
        }
    };

    return (
        <Box sx={{ width: '100%' }}>
            <Box
                sx={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    marginBottom: 3,
                    paddingY: 1,
                }}
            >
                <Box
                    sx={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 1.5,
                        flex: 1,
                    }}
                >
                    {onBack && (
                        <IconButton
                            onClick={() => {
                                if (typeof onBack === 'string' && window[onBack]) {
                                    window[onBack]();
                                } else if (typeof onBack === 'function') {
                                    onBack();
                                }
                            }}
                            sx={{
                                padding: 1,
                                '&:hover': {
                                    backgroundColor: 'rgba(0, 0, 0, 0.04)',
                                },
                            }}
                            aria-label="Go back"
                        >
                            <ArrowLeftIcon size="md" />
                        </IconButton>
                    )}
                    <FAWTypography
                        variant="h6"
                        sx={{
                            fontWeight: 600,
                            fontSize: '22px',
                            lineHeight: '28px',
                            color: colors.type.default,
                        }}
                    >
                        Create Workflow Summary
                    </FAWTypography>
                </Box>
            </Box>

            <Box sx={{ p: 3, maxHeight: 'calc(100vh - 200px)', overflowY: 'auto' }}>
                <Box sx={{ mb: 3 }}>
                    <FAWTypography
                        variant="body1"
                        sx={{
                            fontWeight: 500,
                            fontSize: '16px',
                            lineHeight: '24px',
                            color: colors.type.default,
                            marginBottom: 2,
                        }}
                    >
                        Select What Workflow Summary includes
                    </FAWTypography>

                    <FormGroup>
                        {options.map((option, index) => {
                            const isChecked = selectedOptions[option.code] || false;
                            const isDisabled = option.dependentOn && !selectedOptions[option.dependentOn];

                            return (
                                <FormControlLabel
                                    key={option.code || index}
                                    control={
                                        <Checkbox
                                            checked={isChecked}
                                            disabled={isDisabled}
                                            onChange={(e) => handleCheckboxChange(option.code, e.target.checked)}
                                        />
                                    }
                                    label={option.name || option.code}
                                    sx={{
                                        marginBottom: 1,
                                        '& .MuiFormControlLabel-label': {
                                            fontSize: '14px',
                                            color: isDisabled ? colors.type.tertiary : colors.type.default,
                                        },
                                    }}
                                />
                            );
                        })}
                    </FormGroup>
                </Box>

                <Box
                    sx={{
                        display: 'flex',
                        gap: 2,
                        justifyContent: 'flex-end',
                        paddingTop: 2,
                        borderTop: `1px solid ${colors.ui.border.static}`,
                    }}
                >
                    <FAWButton
                        variant="outlined"
                        onClick={() => {
                            if (typeof onBack === 'string' && window[onBack]) {
                                window[onBack]();
                            } else if (typeof onBack === 'function') {
                                onBack();
                            }
                        }}
                        disabled={isSubmitting}
                    >
                        Cancel
                    </FAWButton>
                    <FAWButton
                        variant="contained"
                        color="primary"
                        onClick={handleGenerate}
                        disabled={isSubmitting}
                    >
                        {isSubmitting ? 'Generating...' : 'Generate'}
                    </FAWButton>
                </Box>
            </Box>
        </Box>
    );
};

export default WorkflowSummaryView;

