import React from 'react';
import { IconButton, Box } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import { showToast } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

const InitiationLogView = ({
  onBack,
  content = ''
}) => {
  return (
    <Box sx={{ width: '100%' }}>
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 3,
          paddingY: 1,
        }}
      >
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            gap: 1.5,
            flex: 1,
          }}
        >
          {onBack && (
            <IconButton
              onClick={() => {
                if (typeof onBack === 'string' && window[onBack]) {
                  window[onBack]();
                } else if (typeof onBack === 'function') {
                  onBack();
                }
              }}
              sx={{
                padding: 1,
                '&:hover': {
                  backgroundColor: 'rgba(0, 0, 0, 0.04)',
                },
              }}
              aria-label="Go back"
            >
              <ArrowLeftIcon size="md" />
            </IconButton>
          )}
          <FAWTypography
            variant="h6"
            sx={{
              fontWeight: 600,
              fontSize: '22px',
              lineHeight: '28px',
              color: colors.type.default,
            }}
          >
            Workflow Initiation Log
          </FAWTypography>
        </Box>
      </Box>

      <Box sx={{ p: 3, maxHeight: 'calc(100vh - 200px)', overflowY: 'auto' }}>
        <Box
          sx={{
            '& *': {
              maxWidth: '100%'
            }
          }}
          dangerouslySetInnerHTML={{ __html: content }}
        />
      </Box>
    </Box>
  );
};

export default InitiationLogView;

