import React, { useState, useEffect } from 'react';
import { IconButton, Box } from '@mui/material';
import FAWButton from '../../FAWButton';
import FAWTypography from '../../FAWTypography';
import FAWRadioGroup from '../../FAWRadioGroup';
import FAWDropdown from '../../FAWDropdown';
import FAWAlert from '../../FAWAlert';
import FAWLoader from '../../FAWLoader';
import { showToast } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

const FLOW_TYPE_AUTO = 'Auto';
const FLOW_TYPE_MANUAL = 'Manual';

const RecategorizeView = ({
  onBack,
  workItemId = 0,
  workflowTypes = [],
  reassignUrl = '/WorkItem/Reassign'
}) => {
  const [flowChangeType, setFlowChangeType] = useState(FLOW_TYPE_MANUAL);
  const [selectedWorkflowDefId, setSelectedWorkflowDefId] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('Recategorizing workflow...');
  const [error, setError] = useState(null);
  const [progressIndex, setProgressIndex] = useState(0);

  useEffect(() => {
    const firstWorkflow = (workflowTypes && workflowTypes.length > 0) ? workflowTypes[0] : null;
    setSelectedWorkflowDefId(firstWorkflow ? (firstWorkflow.Value || firstWorkflow.value || '') : '');
  }, [workflowTypes]);

  useEffect(() => {
    if (isSubmitting) {
      const interval = setInterval(() => {
        if (loadingMessage === 'Recategorization complete. Redirecting please wait...') {
          return;
        }
        setProgressIndex(prev => {
          const newIndex = prev + 1;
          if (newIndex === 3) {
            setLoadingMessage('still working...');
          } else if (newIndex === 5) {
            setLoadingMessage('recategorization taking longer than expected...');
          }
          return newIndex;
        });
      }, 1000);

      return () => clearInterval(interval);
    }
  }, [isSubmitting, loadingMessage]);

  const handleFlowTypeChange = (event) => {
    setFlowChangeType(event.target.value);
  };

  const handleWorkflowDefChange = (selectedOption, event) => {
    setSelectedWorkflowDefId(selectedOption ? selectedOption.value : '');
  };

  const handleSubmit = async () => {
    if (flowChangeType === FLOW_TYPE_MANUAL && !selectedWorkflowDefId) {
      const errorMsg = 'Please select a workflow type';
      setError(errorMsg);
      showToast.error(errorMsg, 30000);
      return;
    }

    setIsSubmitting(true);
    setError(null);
    setLoadingMessage('Recategorizing workflow...');
    setProgressIndex(0);

    const formData = new FormData();
    formData.append('WorkItemId', workItemId.toString());
    formData.append('FlowChangeType', flowChangeType);
    if (flowChangeType === FLOW_TYPE_MANUAL) {
      formData.append('WorkflowDefId', selectedWorkflowDefId);
    }

    const csrfToken = document.querySelector('input[name="__RequestVerificationToken"]')?.value || '';

    try {
      const response = await fetch(reassignUrl, {
        method: 'POST',
        headers: {
          'RequestVerificationToken': csrfToken
        },
        body: formData
      });

      if (!response.ok) {
        throw new Error('Recategorization failed');
      }

      const data = await response.json();
      
      if (data.Url) {
        showToast.success('Workflow recategorized successfully', 30000);
        setLoadingMessage('Recategorization complete. Redirecting please wait...');
        setTimeout(() => {
          window.location.replace(`${window.location.origin}${data.Url}`);
        }, 500);
      } else {
        const errorMsg = 'Something went wrong recategorizing workflow.';
        setError(errorMsg);
        showToast.error(errorMsg, 30000);
        setIsSubmitting(false);
      }
    } catch (err) {
      const errorMsg = 'Something went wrong recategorizing workflow.';
      setError(errorMsg);
      showToast.error(errorMsg, 30000);
      setIsSubmitting(false);
    }
  };

  const handleCancel = () => {
    if (!isSubmitting && onBack) {
      if (typeof onBack === 'string' && window[onBack]) {
        window[onBack]();
      } else if (typeof onBack === 'function') {
        onBack();
      }
    }
  };

  const workflowOptions = (workflowTypes || []).map(type => ({
    value: type.Value || type.value || '',
    label: type.Text || type.text || ''
  }));

  return (
    <Box sx={{ width: '100%' }}>
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 3,
          paddingY: 1,
        }}
      >
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            gap: 1.5,
            flex: 1,
          }}
        >
          {onBack && (
            <IconButton
              onClick={handleCancel}
              disabled={isSubmitting}
              sx={{
                padding: 1,
                '&:hover': {
                  backgroundColor: 'rgba(0, 0, 0, 0.04)',
                },
              }}
              aria-label="Go back"
            >
              <ArrowLeftIcon size="md" />
            </IconButton>
          )}
          <FAWTypography
            variant="h6"
            sx={{
              fontWeight: 600,
              fontSize: '22px',
              lineHeight: '28px',
              color: colors.type.default,
            }}
          >
            Recategorize Workflow
          </FAWTypography>
        </Box>
      </Box>

      <Box sx={{ p: 3 }}>
        {error && (
          <FAWAlert severity="error" message={error} onClose={() => setError(null)} sx={{ mb: 2 }} />
        )}

        {isSubmitting ? (
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', py: 4 }}>
            <FAWLoader label={loadingMessage} inline={false} size={40} />
          </Box>
        ) : (
          <Box>
            <Box sx={{ 
              border: `1px solid ${colors.ui.border.static}`, 
              borderRadius: '4px', 
              padding: '10px', 
              margin: '10px 0' 
            }}>
              <FAWRadioGroup
                id="flowChangeType"
                value={flowChangeType}
                onChange={handleFlowTypeChange}
                options={[
                  {
                    value: FLOW_TYPE_AUTO,
                    label: "Have system re-assign according to established rules"
                  },
                  {
                    value: FLOW_TYPE_MANUAL,
                    label: "Manually select"
                  }
                ]}
                sx={{ mb: 1 }}
              />
              {flowChangeType === FLOW_TYPE_MANUAL && (
                <Box sx={{ ml: 4, mt: 2 }}>
                  <FAWDropdown
                    id="WorkflowDefId"
                    label="Workflow Type"
                    value={selectedWorkflowDefId}
                    options={workflowOptions}
                    onChange={handleWorkflowDefChange}
                    size="small"
                    sx={{ minWidth: 200 }}
                  />
                </Box>
              )}
            </Box>

            <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end', marginTop: 3, paddingTop: 3, borderTop: `1px solid ${colors.ui.border.static}` }}>
              <FAWButton
                variant="outlined"
                color="inherit"
                onClick={handleCancel}
                disabled={isSubmitting}
              >
                Cancel
              </FAWButton>
              <FAWButton
                variant="contained"
                color="primary"
                onClick={handleSubmit}
                disabled={isSubmitting || (flowChangeType === FLOW_TYPE_MANUAL && !selectedWorkflowDefId)}
              >
                Save
              </FAWButton>
            </Box>
          </Box>
        )}
      </Box>
    </Box>
  );
};

export default RecategorizeView;

