import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { ThemeProvider } from '@mui/material/styles';
import {
  Button,
  IconButton,
  Menu,
  MenuItem,
  ListItemIcon,
  ListItemText,
  Box,
  Badge,
  CircularProgress,
} from '@mui/material';
import { fawMuiTheme } from '../../../Theme/FAWThemeProvider';
import FAWTypography from '../../FAWTypography';
import FAWTooltip from '../../FAWTooltip';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import { showToast, ToastManager } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import MoreIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/More.js";
import AttachIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Attach.js";
import ExternalLinkIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExternalLink.js";
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";
import ExpandDownIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExpandDown.js";
import SearchIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Search.js";
import AssurancePlansIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/AssurancePlans.js";
import SummarizeIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Summarize.js";
import ReloadIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Reload.js";
import AttachmentView from './AttachmentView';
import InitiationLogView from './InitiationLogView';
import WorkflowSummaryView from './WorkflowSummaryView';
import RecategorizeView from './RecategorizeView';
import FindAdditionalFieldsView from './FindAdditionalFieldsView';

const WORKFLOW_ROOT_ID = 'workflow-root';
const WORK_ITEM_CARDS_CONTAINER_ID = 'workItemDetailsCardsContainer';
const LEAVING_OVERLAY_ID = 'work-item-leaving-overlay';

let workItemLeavingOverlayRoot = null;

/**
 * Helper function to convert hex color to rgba
 */
const hexToRgba = (hex, alpha = 1) => {
  if (!hex || typeof hex !== 'string') return null;
  const cleanHex = hex.replace('#', '');
  if (cleanHex.length !== 6) return null;
  const r = parseInt(cleanHex.substr(0, 2), 16);
  const g = parseInt(cleanHex.substr(2, 2), 16);
  const b = parseInt(cleanHex.substr(4, 2), 16);
  if (Number.isNaN(r) || Number.isNaN(g) || Number.isNaN(b)) return null;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

function workItemLeavingBackdropColor() {
  const overlay =
    typeof colors?.background?.overlay === 'string' && colors.background.overlay.trim()
      ? colors.background.overlay
      : null;
  const base = colors?.background?.default;
  return (
    overlay ||
    (base && base.startsWith('#') ? hexToRgba(base, 0.96) : null) ||
    'rgba(255, 255, 255, 0.96)'
  );
}

/**
 * Imperative full-viewport MUI CircularProgress on document.body (createRoot + ThemeProvider).
 * Escapes soon-hidden header subtree so the loader always paints with app theme.
 */
function showSyncWorkItemLeavingOverlay() {
  if (typeof document === 'undefined' || !document.body) {
    return;
  }
  const existing = document.getElementById(LEAVING_OVERLAY_ID);
  if (existing) {
    if (workItemLeavingOverlayRoot) {
      workItemLeavingOverlayRoot.unmount();
      workItemLeavingOverlayRoot = null;
    }
    existing.remove();
  }

  const el = document.createElement('div');
  el.id = LEAVING_OVERLAY_ID;
  el.setAttribute('role', 'status');
  el.setAttribute('aria-live', 'polite');
  el.setAttribute('aria-label', 'Loading');
  document.body.appendChild(el);

  const backdrop = workItemLeavingBackdropColor();
  workItemLeavingOverlayRoot = createRoot(el);
  workItemLeavingOverlayRoot.render(
    <ThemeProvider theme={fawMuiTheme}>
      <Box
        sx={{
          position: 'fixed',
          inset: 0,
          zIndex: 2147483000,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          bgcolor: backdrop,
        }}
      >
        <CircularProgress size={48} />
      </Box>
    </ThemeProvider>
  );
}

/**
 * Hide workflow + detail cards before navigation.
 * Do not hide #main-workitem-div — WorkItemHeader (tooltips/menus) lives inside it; display:none
 * invalidates MUI Popper anchorEl and triggers console warnings.
 */
function hideWorkItemContentForBackNavigation() {
  const workflowRoot = document.getElementById(WORKFLOW_ROOT_ID);
  if (workflowRoot) {
    workflowRoot.style.display = 'none';
  }
  const cards = document.getElementById(WORK_ITEM_CARDS_CONTAINER_ID);
  if (cards) {
    cards.style.display = 'none';
  }
}

const WorkItemHeader = ({
  title = '',
  backUrl = '',
  onBackClick,
  onThirdPartyProfileClick,
  showThirdPartyProfile = true,
  showActions = true,
  showAttachments = false,
  canGenerateCaseSummary = false,
  canReassignCase = false,
  workItemId = 0,
  relateTypeCode = '',
  sourceElement = 'WorkItemAttachmentButton',
  initialAttachments = []
}) => {
  const [actionsMenuAnchor, setActionsMenuAnchor] = useState(null);
  const [currentView, setCurrentView] = useState('main');
  const [viewProps, setViewProps] = useState({});

  useEffect(() => {
    window.setWorkItemView = (viewName, props = {}) => {
      setCurrentView(viewName);
      setViewProps(props);
      
      const cardsContainer = document.getElementById('workItemDetailsCardsContainer');
      const workflowRoot = document.getElementById('workflow-root');
      const processFlowDetail = document.querySelector('#processFlowStepDetail');
      
      if (viewName === 'main') {
        if (cardsContainer) cardsContainer.style.display = '';
        if (workflowRoot) workflowRoot.style.display = '';
        if (processFlowDetail) processFlowDetail.style.display = '';
      } else {
        if (cardsContainer) cardsContainer.style.display = 'none';
        if (workflowRoot) workflowRoot.style.display = 'none';
        if (processFlowDetail) processFlowDetail.style.display = 'none';
      }
    };
    
    window.showWorkItemMainView = () => {
      setCurrentView('main');
      setViewProps({});
      
      const cardsContainer = document.getElementById('workItemDetailsCardsContainer');
      const workflowRoot = document.getElementById('workflow-root');
      const processFlowDetail = document.querySelector('#processFlowStepDetail');
      
      if (cardsContainer) cardsContainer.style.display = '';
      if (workflowRoot) workflowRoot.style.display = '';
      if (processFlowDetail) processFlowDetail.style.display = '';
    };

    return () => {
      if (window.setWorkItemView) delete window.setWorkItemView;
      if (window.showWorkItemMainView) delete window.showWorkItemMainView;
    };
  }, []);

  const handleBackClick = () => {
    if (onBackClick) {
      if (typeof onBackClick === 'string') {
        const fn = window[onBackClick];
        if (typeof fn === 'function') fn();
      } else {
        onBackClick();
      }
    } else if (backUrl) {
      setActionsMenuAnchor(null);
      if (typeof document !== 'undefined' && document.activeElement instanceof HTMLElement) {
        document.activeElement.blur();
      }
      showSyncWorkItemLeavingOverlay();
      hideWorkItemContentForBackNavigation();

      const navigate = () => {
        window.location.assign(backUrl);
      };

      window.requestAnimationFrame(() => {
        window.requestAnimationFrame(navigate);
      });
    }
  };

  const handleButtonClick = (handler) => {
    if (!handler) return;
    if (typeof handler === 'string') {
      const fn = window[handler];
      if (typeof fn === 'function') {
        fn();
      }
    } else if (typeof handler === 'function') {
      handler();
    }
  };

  const handleActionsMenuOpen = (event) => {
    setActionsMenuAnchor(event.currentTarget);
  };

  const handleActionsMenuClose = () => {
    setActionsMenuAnchor(null);
  };

  const handleMenuAction = (actionHandler) => {
    handleActionsMenuClose();
    setTimeout(() => {
      handleButtonClick(actionHandler);
    }, 100);
  };

  return (
    <FAWErrorBoundary
      title="Work Item Header Error"
      message="An error occurred while rendering the work item header."
      showDetails={false}
    >
      <ToastManager />
      <Box sx={{ width: '100%' }}>
        {currentView === 'main' && (
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              marginBottom: 3,
              paddingY: 1,
            }}
          >
            {(backUrl || onBackClick) && (
              <FAWTooltip title="Go back">
                <IconButton
                  onClick={handleBackClick}
                  sx={{
                    padding: 1,
                    '&:hover': {
                      backgroundColor: 'rgba(0, 0, 0, 0.04)',
                    },
                  }}
                  aria-label="Go back"
                >
                  <ArrowLeftIcon size="md" />
                </IconButton>
              </FAWTooltip>
            )}
            {title && (
              <FAWTypography
                variant="h6"
                sx={{
                  fontWeight: 600,
                  fontSize: '22px',
                  lineHeight: '28px',
                  color: colors.type.default,
                }}
              >
                {title}
              </FAWTypography>
            )}
          </Box>
        )}

        {currentView !== 'main' && (
          <>
            {currentView === 'attachment' && (
              <AttachmentView
                onBack="showWorkItemMainView"
                relateId={workItemId}
                relateTypeCode={relateTypeCode}
                sourceElement={sourceElement}
                initialAttachments={initialAttachments}
              />
            )}
            {currentView === 'initiationLog' && (
              <InitiationLogView
                onBack="showWorkItemMainView"
                content={viewProps.content || ''}
              />
            )}
            {currentView === 'summary' && (
              <WorkflowSummaryView
                onBack="showWorkItemMainView"
                workItemId={viewProps.workItemId || workItemId}
                options={viewProps.options || []}
                generateUrl={viewProps.generateUrl || '/WorkItem/GenerateCaseSummary'}
              />
            )}
            {currentView === 'recategorize' && (
              <RecategorizeView
                onBack="showWorkItemMainView"
                workItemId={viewProps.workItemId || workItemId}
                workflowTypes={viewProps.workflowTypes || []}
                reassignUrl={viewProps.reassignUrl || '/WorkItem/Reassign'}
              />
            )}
            {currentView === 'findAdditionalFields' && (
              <FindAdditionalFieldsView
                onBack="showWorkItemMainView"
                workItemId={viewProps.workItemId || workItemId}
                searchUrl={viewProps.searchUrl || '/WorkItem/SearchUDFsApi'}
              />
            )}
          </>
        )}
      </Box>
    </FAWErrorBoundary>
  );
};

export default WorkItemHeader;

